// ─────────────────────────────────────────────
// UNIVERSAL AI CALLER  (respects settings.aiProvider: groq | anthropic | ollama)
// ─────────────────────────────────────────────
async function callAI(prompt, settings, maxTokens = 600) {
  const provider = settings.aiProvider || 'groq';
  if (provider === 'ollama') {
    const ollamaUrl = settings.ollamaUrl || 'http://localhost:11434';
    const model = settings.aiModel || 'llama3.2';
    const res = await fetch(`${ollamaUrl}/api/generate`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model, prompt, stream: false })
    });
    const data = await res.json();
    return data.response || 'No response.';
  }
  const apiKey = provider === 'groq' ? settings.groqKey : settings.anthropicKey;
  if (!apiKey) throw new Error(
    provider === 'groq'
      ? '⚠️ No Groq key. Go to ⚙️ Settings → AI → paste your free Groq key (console.groq.com).'
      : '⚠️ No Anthropic key. Go to ⚙️ Settings → AI → paste your Anthropic key.'
  );
  if (provider === 'groq') {
    const res = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model: 'llama-3.1-8b-instant', max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] })
    });
    const data = await res.json();
    if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));
    return data.choices?.[0]?.message?.content || 'No response.';
  }
  // Anthropic
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json', 'x-api-key': apiKey,
      'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({ model: 'claude-haiku-4-5-20251001', max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] })
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message);
  return data.content?.[0]?.text || 'No response.';
}

async function callAIChat(messages, settings, maxTokens = 600) {
  const provider = settings.aiProvider || 'groq';
  if (provider === 'ollama') {
    const ollamaUrl = settings.ollamaUrl || 'http://localhost:11434';
    const model = settings.aiModel || 'llama3.2';
    const res = await fetch(`${ollamaUrl}/api/chat`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model, stream: false, messages })
    });
    const data = await res.json();
    return data.message?.content || 'No response.';
  }
  const apiKey = provider === 'groq' ? settings.groqKey : settings.anthropicKey;
  if (!apiKey) throw new Error(
    provider === 'groq'
      ? '⚠️ No Groq key. Go to ⚙️ Settings → AI → paste your free Groq key.'
      : '⚠️ No Anthropic key. Go to ⚙️ Settings → AI → paste your Anthropic key.'
  );
  if (provider === 'groq') {
    const res = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model: 'llama-3.1-8b-instant', max_tokens: maxTokens, messages })
    });
    const data = await res.json();
    if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));
    return data.choices?.[0]?.message?.content || 'No response.';
  }
  // Anthropic — extract system message
  const sysMsg = messages.find(m => m.role === 'system');
  const chatMsgs = messages.filter(m => m.role !== 'system');
  const body = { model: 'claude-haiku-4-5-20251001', max_tokens: maxTokens, messages: chatMsgs };
  if (sysMsg) body.system = sysMsg.content;
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json', 'x-api-key': apiKey,
      'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify(body)
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message);
  return data.content?.[0]?.text || 'No response.';
}

// ─────────────────────────────────────────────
// ERROR BOUNDARY — prevents white pages on runtime errors
// ─────────────────────────────────────────────
class ErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, info) { console.error('LifeOS render error:', error, info); }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: 32, textAlign: 'center', background: '#0b0b18', minHeight: '100vh', color: '#eeeeff' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>⚠️</div>
          <div style={{ fontSize: 20, marginBottom: 8, color: '#ff3d6b' }}>Something went wrong in this section</div>
          <div style={{ fontSize: 13, color: '#5e5e96', marginBottom: 24 }}>{this.state.error?.message}</div>
          <button onClick={() => this.setState({ hasError: false, error: null })}
            style={{ padding: '10px 24px', background: '#7c6fff', color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer', fontSize: 14 }}>
            🔄 Try Again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}



