// ─────────────────────────────────────────────

// ─────────────────────────────────────────────
// PORTFOLIO HUB (Investments + Markets merged + AI picks)
// ─────────────────────────────────────────────
function PortfolioHubTab({ T, s, investments, setInvestments, settings, expenses, addXP, assets, setAssets, thisMonthIncome, thisMonthSpend, savingsRate, debts, selectedMonthRemaining, tradeJournal, setTradeJournal, priceAlerts, setPriceAlerts, goals, setGoals }) {
  const [subTab, setSubTab] = useState('portfolio');
  const [aiChat, setAiChat] = useState([]);
  const [aiInput, setAiInput] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [riskProfile, setRiskProfile] = useState('moderate');
  const [horizon, setHorizon] = useState('medium');
  // C15-C17: Trade journal state
  const [tradeForm, setTradeForm] = useState({ symbol:'', type:'buy', qty:'', price:'', date:today(), linkedGoalId:'' });
  const [showTradeForm, setShowTradeForm] = useState(false);
  // C18: Price alert state
  const [alertForm, setAlertForm] = useState({ symbol:'', direction:'above', target:'' });
  const [showAlertForm, setShowAlertForm] = useState(false);

  function addTrade() {
    if (!tradeForm.symbol || !tradeForm.qty || !tradeForm.price) return;
    const qty = Number(tradeForm.qty);
    const price = Number(tradeForm.price);
    const total = qty * price;
    const trade = { id: Date.now(), ...tradeForm, qty, price, total };
    setTradeJournal(j => [...(j||[]), trade]);
    // C15 — update matching investment P&L
    if (tradeForm.type === 'sell') {
      const inv = investments.find(i => (i.symbol||'').toUpperCase() === tradeForm.symbol.toUpperCase());
      if (inv) {
        const pnl = (price - inv.buyPrice) * Math.min(qty, inv.quantity);
        // C16 — offer to apply profit to a goal
        if (pnl > 0 && goals && goals.length > 0) {
          const openGoals = goals.filter(g => (g.progress||0) < g.target);
          if (openGoals.length > 0 && tradeForm.linkedGoalId) {
            const g = openGoals.find(x => String(x.id) === String(tradeForm.linkedGoalId));
            if (g) setGoals(gs => gs.map(x => x.id===g.id ? {...x, progress: Math.min(x.target, (x.progress||0)+pnl)} : x));
          }
        }
      }
    }
    addXP(5, `Trade logged: ${tradeForm.type.toUpperCase()} ${tradeForm.symbol}`);
    setTradeForm({ symbol:'', type:'buy', qty:'', price:'', date:today(), linkedGoalId:'' });
    setShowTradeForm(false);
  }

  function addPriceAlert() {
    if (!alertForm.symbol || !alertForm.target) return;
    setPriceAlerts(a => [...(a||[]), { id: Date.now(), ...alertForm, target: Number(alertForm.target) }]);
    setAlertForm({ symbol:'', direction:'above', target:'' });
    setShowAlertForm(false);
  }

  // C17 — Total capital allocated in trades (buy side not yet sold)
  const allocatedCapital = useMemo(() => {
    if (!tradeJournal) return 0;
    const buys = tradeJournal.filter(t=>t.type==='buy').reduce((s,t)=>s+t.total,0);
    const sells = tradeJournal.filter(t=>t.type==='sell').reduce((s,t)=>s+t.total,0);
    return Math.max(0, buys - sells);
  }, [tradeJournal]);

  // Portfolio calculations
  const totalInvested = investments.reduce((s,i)=>s+i.buyPrice*i.quantity,0);
  const currentValue  = investments.reduce((s,i)=>s+(i.currentPrice??i.buyPrice)*i.quantity,0);
  const totalPnL      = currentValue - totalInvested;
  const totalReturn   = totalInvested>0?(totalPnL/totalInvested)*100:0;

  // Cash surplus calculation — use MoneyHub's selectedMonthRemaining if passed (B14), else fall back
  const monthlySurplus = selectedMonthRemaining !== undefined ? selectedMonthRemaining : (thisMonthIncome - thisMonthSpend);
  const totalDebt      = debts.reduce((s,d)=>s+Number(d.balance||0),0);
  const cashAssets     = assets.filter(a=>a.type==='Cash').reduce((s,a)=>s+Number(a.value||0),0);

  function buildPortfolioContext() {
    const positions = investments.map(i=>{
      const val=(i.currentPrice??i.buyPrice)*i.quantity;
      const pnl=((i.currentPrice??i.buyPrice)-i.buyPrice)*i.quantity;
      const pnlPct=((i.currentPrice??i.buyPrice)-i.buyPrice)/i.buyPrice*100;
      return `${i.symbol} (${i.type||'Stock'}): ${i.quantity} units @ buy ${settings.currency}${i.buyPrice} | current ${settings.currency}${i.currentPrice??i.buyPrice} | value ${settings.currency}${fmtN(val)} | P&L ${pnl>=0?'+':''}${settings.currency}${fmtN(pnl)} (${pnlPct.toFixed(1)}%)`;
    }).join('\n');
    // C24 — emergency fund months covered
    const avgMonthlySpend = thisMonthSpend || 1;
    const efMonths = cashAssets / avgMonthlySpend;
    const efWarning = efMonths < 3 ? `⚠️ IMPORTANT: User only has ${efMonths.toFixed(1)} months of emergency fund (target: 3-6 months). Strongly recommend building emergency fund BEFORE investing more.` : `✅ Emergency fund: ${efMonths.toFixed(1)} months covered (healthy).`;
    return `PORTFOLIO SUMMARY:
Total invested: ${settings.currency}${fmtN(totalInvested)}
Current value: ${settings.currency}${fmtN(currentValue)}
Total P&L: ${totalPnL>=0?'+':''}${settings.currency}${fmtN(totalPnL)} (${totalReturn.toFixed(1)}%)

POSITIONS:
${positions||'No positions yet'}

FINANCIAL CONTEXT:
Monthly income: ${settings.currency}${fmtN(thisMonthIncome)}
Monthly spend: ${settings.currency}${fmtN(thisMonthSpend)}
Monthly surplus available to invest: ${settings.currency}${fmtN(monthlySurplus)}
Cash reserves: ${settings.currency}${fmtN(cashAssets)}
Total debt: ${settings.currency}${fmtN(totalDebt)}
Savings rate: ${savingsRate.toFixed(1)}%
${efWarning}

RISK PROFILE: ${riskProfile}
TIME HORIZON: ${horizon}`;
  }

  async function sendAI(msg) {
    if(!msg.trim())return;
    const userMsg={role:'user',content:msg};
    const newHistory=[...aiChat,userMsg];
    setAiChat(newHistory);setAiInput('');setAiLoading(true);
    const context=buildPortfolioContext();
    const messages=newHistory.map(m=>m.role==='user'?`User: ${m.content}`:`AI: ${m.content}`).join('\n');
    try{
      const prompt=`You are an investment advisor AI. IMPORTANT: For educational purposes only.\n\n${context}\n\nConversation:\n${messages}\n\nAI:`;
      const reply = await callAI(prompt, settings, 500);
      setAiChat(h=>[...h,{role:'ai',content:reply}]);
    }catch(e){setAiChat(h=>[...h,{role:'ai',content:'⚠️ AI error: '+e.message}]);}
    setAiLoading(false);
  }

  async function analyzeSurplus(){
    const prompt=`Based on my financial data, I have ${settings.currency}${fmtN(monthlySurplus)} in monthly surplus. Where should I put it? Consider: my existing portfolio, my debt (${settings.currency}${fmtN(totalDebt)}), cash reserves (${settings.currency}${fmtN(cashAssets)}), and risk profile (${riskProfile}). Give me a specific allocation in % with reasoning. Focus on practical steps.`;
    await sendAI(prompt);
  }

  return (
    <div style={{display:'flex',flexDirection:'column',gap:'16px'}}>
      <div style={{fontFamily:"'Exo 2',sans-serif",fontSize:'22px',fontWeight:'900'}}>💹 Portfolio Hub</div>
      <div className="los-tab-strip">
        {[{id:'portfolio',label:'💹 Portfolio'},{id:'markets',label:'📈 Markets'},{id:'trades',label:'📒 Trades'},{id:'alerts',label:'🔔 Alerts'},{id:'advisor',label:'🤖 AI Advisor'}].map(st=>(
          <button key={st.id} onClick={()=>setSubTab(st.id)} style={{...s.btnGhost,fontSize:13,padding:'8px 18px',background:subTab===st.id?T.accentSoft:'transparent',color:subTab===st.id?T.accent:T.textMuted,borderColor:subTab===st.id?T.accent+'55':T.border,fontWeight:subTab===st.id?'700':'400'}}>{st.label}</button>
        ))}
      </div>

      {subTab==='portfolio' && (
        <InvestmentsTab T={T} s={s} investments={investments} setInvestments={setInvestments} settings={settings} expenses={expenses} addXP={addXP} thesisDates={thesisDates||{}} setThesisDates={setThesisDates||(() => {})} />
      )}
      {subTab==='markets' && (
        <MarketsTab T={T} s={s} assets={assets} setAssets={setAssets} investments={investments} setInvestments={setInvestments} settings={settings} />
      )}

      {/* C15-C17: Trade Journal */}
      {subTab==='trades' && (
        <div style={{display:'flex',flexDirection:'column',gap:'16px'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
            <div style={s.cardTitle}>📒 Trade Journal</div>
            <button style={s.btn()} onClick={()=>setShowTradeForm(!showTradeForm)}>+ Log Trade</button>
          </div>
          {/* C17 — Allocated capital banner */}
          {allocatedCapital > 0 && (
            <div style={{...s.card,background:`${T.warning}11`,border:`1px solid ${T.warning}44`}}>
              <span style={{fontSize:'12px',color:T.warning}}>💼 Allocated trading capital: <strong>{settings.currency}{fmtN(allocatedCapital)}</strong> — deducted from investable surplus</span>
            </div>
          )}
          {showTradeForm && (
            <div style={{...s.card,border:`1px solid ${T.accent}44`}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:'8px',marginBottom:'8px'}}>
                <input style={s.input} placeholder="Symbol (e.g. AAPL)" value={tradeForm.symbol} onChange={e=>setTradeForm(f=>({...f,symbol:e.target.value.toUpperCase()}))} />
                <select style={s.select} value={tradeForm.type} onChange={e=>setTradeForm(f=>({...f,type:e.target.value}))}>
                  <option value="buy">Buy</option>
                  <option value="sell">Sell</option>
                </select>
                <input type="date" style={s.input} value={tradeForm.date} onChange={e=>setTradeForm(f=>({...f,date:e.target.value}))} />
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'8px',marginBottom:'8px'}}>
                <input type="number" style={s.input} placeholder="Quantity" value={tradeForm.qty} onChange={e=>setTradeForm(f=>({...f,qty:e.target.value}))} />
                <input type="number" style={s.input} placeholder={`Price (${settings.currency})`} value={tradeForm.price} onChange={e=>setTradeForm(f=>({...f,price:e.target.value}))} />
              </div>
              {/* C16 — Link sell profit to a goal */}
              {tradeForm.type === 'sell' && (goals||[]).length > 0 && (
                <select style={{...s.select,marginBottom:'8px',width:'100%'}} value={tradeForm.linkedGoalId} onChange={e=>setTradeForm(f=>({...f,linkedGoalId:e.target.value}))}>
                  <option value="">Apply profit to goal (optional)…</option>
                  {(goals||[]).filter(g=>(g.progress||0)<g.target).map(g=><option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
              )}
              <div style={{display:'flex',gap:'8px'}}>
                <button style={s.btn()} onClick={addTrade}>Save Trade</button>
                <button style={s.btnGhost} onClick={()=>setShowTradeForm(false)}>Cancel</button>
              </div>
            </div>
          )}
          {(tradeJournal||[]).length === 0 && <div style={{...s.card,textAlign:'center',color:T.textMuted,padding:'32px'}}>No trades logged yet.</div>}
          <div style={{display:'flex',flexDirection:'column',gap:'8px'}}>
            {[...(tradeJournal||[])].reverse().map(t=>{
              const isBuy = t.type==='buy';
              return (
                <div key={t.id} style={{...s.card,display:'flex',justifyContent:'space-between',alignItems:'center',gap:'8px'}}>
                  <span style={{...s.tag(isBuy?T.success:T.danger),fontSize:'11px',fontWeight:'800'}}>{t.type.toUpperCase()}</span>
                  <span style={{fontWeight:'700',fontSize:'14px'}}>{t.symbol}</span>
                  <span style={{fontSize:'12px',color:T.textMuted}}>{t.qty} × {settings.currency}{fmtN(t.price)}</span>
                  <span style={{fontWeight:'700',color:isBuy?T.text:T.success}}>{isBuy?'-':'+?'}{settings.currency}{fmtN(t.total)}</span>
                  <span style={{fontSize:'11px',color:T.textMuted}}>{t.date}</span>
                  <button style={{...s.btnGhost,color:T.danger,padding:'2px 6px',fontSize:'12px'}} onClick={()=>setTradeJournal(j=>j.filter(x=>x.id!==t.id))}>✕</button>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* C18: Price Alerts */}
      {subTab==='alerts' && (
        <div style={{display:'flex',flexDirection:'column',gap:'16px'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
            <div style={s.cardTitle}>🔔 Price Alerts</div>
            <button style={s.btn()} onClick={()=>setShowAlertForm(!showAlertForm)}>+ Add Alert</button>
          </div>
          <div style={{...s.card,background:`${T.accent}0a`,fontSize:'12px',color:T.textMuted}}>
            Alerts trigger in Dashboard Smart Alerts when an investment's current price crosses your target.
          </div>
          {showAlertForm && (
            <div style={{...s.card,border:`1px solid ${T.accent}44`}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:'8px',marginBottom:'8px'}}>
                <input style={s.input} placeholder="Symbol (e.g. AAPL)" value={alertForm.symbol} onChange={e=>setAlertForm(f=>({...f,symbol:e.target.value.toUpperCase()}))} />
                <select style={s.select} value={alertForm.direction} onChange={e=>setAlertForm(f=>({...f,direction:e.target.value}))}>
                  <option value="above">📈 Price above</option>
                  <option value="below">📉 Price below</option>
                </select>
                <input type="number" style={s.input} placeholder={`Target (${settings.currency})`} value={alertForm.target} onChange={e=>setAlertForm(f=>({...f,target:e.target.value}))} />
              </div>
              <div style={{display:'flex',gap:'8px'}}>
                <button style={s.btn()} onClick={addPriceAlert}>Set Alert</button>
                <button style={s.btnGhost} onClick={()=>setShowAlertForm(false)}>Cancel</button>
              </div>
            </div>
          )}
          {(priceAlerts||[]).length === 0 && <div style={{...s.card,textAlign:'center',color:T.textMuted,padding:'32px'}}>No price alerts set.</div>}
          <div style={{display:'flex',flexDirection:'column',gap:'8px'}}>
            {(priceAlerts||[]).map(a=>{
              const inv = investments.find(i=>(i.symbol||'').toUpperCase()===a.symbol);
              const current = inv ? (inv.currentPrice??inv.buyPrice) : null;
              const triggered = current && ((a.direction==='above' && current>=a.target)||(a.direction==='below' && current<=a.target));
              return (
                <div key={a.id} style={{...s.card,display:'flex',justifyContent:'space-between',alignItems:'center',gap:'8px',border:`1px solid ${triggered?T.warning+'66':T.border}`}}>
                  <span style={{fontWeight:'700'}}>{a.symbol}</span>
                  <span style={{fontSize:'12px',color:T.textMuted}}>{a.direction==='above'?'📈 above':'📉 below'} {settings.currency}{fmtN(a.target)}</span>
                  {current && <span style={{fontSize:'12px',color:triggered?T.warning:T.success}}>Now: {settings.currency}{fmtN(current)}</span>}
                  {triggered && <span style={{...s.tag(T.warning),fontSize:'10px'}}>🔔 Triggered!</span>}
                  <button style={{...s.btnGhost,color:T.danger,padding:'2px 6px',fontSize:'12px'}} onClick={()=>setPriceAlerts(a2=>a2.filter(x=>x.id!==a.id))}>✕</button>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ── AI ADVISOR ── */}
      {subTab==='advisor' && (
        <div style={{display:'flex',flexDirection:'column',gap:'16px'}}>
          {/* C24 — Emergency fund warning */}
          {(() => {
            const efMonths = thisMonthSpend > 0 ? cashAssets / thisMonthSpend : 0;
            if (efMonths < 3) return (
              <div style={{...s.card,border:`1px solid ${T.warning}55`,background:`${T.warning}11`}}>
                <div style={{display:'flex',gap:'10px',alignItems:'center'}}>
                  <span style={{fontSize:'24px'}}>🛡️</span>
                  <div>
                    <div style={{fontWeight:'700',color:T.warning,marginBottom:'2px'}}>Build Your Emergency Fund First</div>
                    <div style={{fontSize:'12px',color:T.textMuted}}>You have {efMonths.toFixed(1)} months of expenses in cash (target: 3–6 months = {settings.currency}{fmtN(thisMonthSpend*3)}–{settings.currency}{fmtN(thisMonthSpend*6)}). Financial advisors recommend securing this before investing.</div>
                  </div>
                </div>
              </div>
            );
            return null;
          })()}
          {/* Surplus spotlight */}
          <div style={{...s.card,border:`1px solid ${monthlySurplus>0?T.success+'55':T.danger+'44'}`,background:`linear-gradient(135deg,${monthlySurplus>0?T.success+'0d':T.danger+'0d'},${T.card})`}}>
            <div style={s.cardTitle}>💰 Monthly Surplus Available to Invest</div>
            <div style={{fontFamily:"'Exo 2',sans-serif",fontSize:'32px',fontWeight:'900',color:monthlySurplus>0?T.success:T.danger,marginBottom:'4px'}}>
              {monthlySurplus>0?'+':''}{settings.currency}{fmtN(monthlySurplus)}
            </div>
            <div style={{fontSize:'12px',color:T.textMuted,marginBottom:'12px'}}>
              Income {settings.currency}{fmtN(thisMonthIncome)} − Spending {settings.currency}{fmtN(thisMonthSpend)}
            </div>
            {monthlySurplus>0
              ? <button style={{...s.btn(T.success),fontSize:'13px',padding:'10px 20px'}} onClick={analyzeSurplus} disabled={aiLoading}>🎯 Where to Put My {settings.currency}{fmtN(monthlySurplus)} Surplus?</button>
              : <div style={{fontSize:'12px',color:T.danger}}>⚠️ No surplus this month. Reduce spending first.</div>
            }
          </div>

          {/* Profile settings */}
          <div style={s.card}>
            <div style={s.cardTitle}>Advisor Profile</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'12px'}}>
              <div>
                <label style={{fontSize:'12px',color:T.textMuted}}>Risk Profile</label>
                <select style={{...s.select,marginTop:'4px'}} value={riskProfile} onChange={e=>setRiskProfile(e.target.value)}>
                  <option value="conservative">Conservative (Capital preservation)</option>
                  <option value="moderate">Moderate (Balanced growth)</option>
                  <option value="aggressive">Aggressive (Max growth)</option>
                </select>
              </div>
              <div>
                <label style={{fontSize:'12px',color:T.textMuted}}>Time Horizon</label>
                <select style={{...s.select,marginTop:'4px'}} value={horizon} onChange={e=>setHorizon(e.target.value)}>
                  <option value="short">Short-term (under 2 years)</option>
                  <option value="medium">Medium (2–7 years)</option>
                  <option value="long">Long-term (7+ years)</option>
                </select>
              </div>
            </div>
          </div>

          {/* Quick actions */}
          <div style={{display:'grid',gridTemplateColumns:s.isMobile?'1fr':'1fr 1fr',gap:'10px'}}>
            {[
              {label:'🔍 Analyze My Portfolio',prompt:'Give me a detailed analysis of my portfolio. What are the strengths, weaknesses, concentration risks, and diversification opportunities?'},
              {label:'👁️ Suggest Watchlist',prompt:'Based on my portfolio and risk profile, suggest 5 assets to add to my watchlist. Explain the thesis for each.'},
              {label:'⚖️ Rebalancing Advice',prompt:'Should I rebalance my portfolio? What would an optimal allocation look like for my risk profile and horizon?'},
              {label:'🏛️ Debt vs Invest',prompt:`I have ${settings.currency}${fmtN(totalDebt)} in debt and ${settings.currency}${fmtN(monthlySurplus)} monthly surplus. Should I pay off debt or invest first? Give me a clear recommendation.`},
            ].map(q=>(
              <button key={q.label} style={{...s.btnGhost,textAlign:'left',padding:'12px 14px',fontSize:'12px',fontWeight:'600'}} onClick={()=>sendAI(q.prompt)} disabled={aiLoading}>{q.label}</button>
            ))}
          </div>

          {/* Chat */}
          {aiChat.length>0&&(
            <div style={{...s.card,border:`1px solid ${T.accent}44`}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'10px'}}>
                <div style={s.cardTitle}>🤖 AI Investment Advisor</div>
                <button style={{...s.btnGhost,fontSize:'11px',padding:'3px 10px'}} onClick={()=>setAiChat([])}>Clear</button>
              </div>
              <div style={{maxHeight:'380px',overflowY:'auto',display:'flex',flexDirection:'column',gap:'10px',marginBottom:'12px'}}>
                {aiChat.map((m,i)=>(
                  <div key={i} style={{display:'flex',gap:'10px',justifyContent:m.role==='user'?'flex-end':'flex-start'}}>
                    <div style={{maxWidth:'80%',padding:'10px 14px',borderRadius:m.role==='user'?'16px 16px 4px 16px':'16px 16px 16px 4px',background:m.role==='user'?T.accent:T.surface,color:m.role==='user'?'#fff':T.text,fontSize:'13px',lineHeight:'1.6',whiteSpace:'pre-wrap'}}>
                      {m.content}
                    </div>
                  </div>
                ))}
                {aiLoading&&<div style={{color:T.textMuted,fontSize:'12px',padding:'8px 14px'}}>🤖 Thinking...</div>}
              </div>
              <div style={{display:'flex',gap:'8px'}}>
                <input style={{...s.input,flex:1}} placeholder="Ask a follow-up — DCA strategy? Crypto allocation? Tax efficiency?" value={aiInput} onChange={e=>setAiInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&!e.shiftKey&&sendAI(aiInput)}/>
                <button style={{...s.btn(),padding:'10px 16px'}} onClick={()=>sendAI(aiInput)} disabled={aiLoading||!aiInput.trim()}>➤</button>
              </div>
            </div>
          )}
          {aiChat.length===0&&(
            <div style={{...s.card,textAlign:'center',color:T.textMuted,padding:'30px 20px',border:`1px solid ${T.border}`}}>
              <div style={{fontSize:'40px',marginBottom:'12px'}}>🤖</div>
              <div style={{fontSize:'13px',marginBottom:'4px'}}>AI Investment Advisor powered by llama3.2</div>
              <div style={{fontSize:'11px'}}>Click a quick action above or ask anything about your portfolio</div>
              <div style={{fontSize:'10px',color:T.textDim,marginTop:'8px'}}>⚠️ Educational purposes only · Not financial advice · Runs locally</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


